const { PDFParse } = require('pdf-parse');
const { interviewReportByAi, generateResumePdf } = require("../services/ai.service");
const interviewReportModel = require("../model/interviewReport.model");

/**
 * 
 * @param {jobdescribe, selfdescribe} req 
 * @param {interviewReport} res 
 * @returns  will return the interview report generated by ai based on the job description ,resume and self description of the candidate
 */
async function generateInterviewController(req, res) {
    try {
        const resumeFile = req.file
        // console.log('hit');

        const { jobdescribe, selfdescribe } = req.body
        
        if (!jobdescribe || !selfdescribe) {
            return res.status(400).json({ message: "jobdescribe is required" })
        }

        if (!resumeFile && !selfdescribe) {
            return res.status(400).json({ message: "Either resume file or self description is required" })
        }

        let resumeContent = { text: "" };
        if (resumeFile) {
            // read pdf buffer using pdf-parse v2 API
            const parser = new PDFParse({ data: resumeFile.buffer })
            try {
                resumeContent = await parser.getText()
            } finally {
                await parser.destroy().catch(() => { })
            }

            //REVIEW - empty PDF text usually means scanned/image-only resume or bad file content.
            if (!resumeContent?.text?.trim()) {
                return res.status(400).json({ message: "unable to extract text from resume pdf" })
            }
        }

        //NOTE - using ai service for creating the interview report based on the job description ,resume and self description of the candidate
        const interviewReportWithAi = await interviewReportByAi({ jobdescribe, resume: resumeContent.text, selfdescribe })
        //NOTE - at the end we are saving the interview report in our database for future reference and also we can show the report to the user in his dashboard
        const interviewReport = await interviewReportModel.create({
            user: req.user.id,
            jobDescription: jobdescribe,
            resume: resumeContent.text,
            selfDescription: selfdescribe,
            ...interviewReportWithAi
        })
        return res.status(200).json({ message: "interview report generated successfully", interviewReport })
    } catch (err) {
        console.log(err)
        //NOTE - service layer attaches statusCode for expected AI/validation failures.
        if (err.statusCode) {
            return res.status(err.statusCode).json({ message: err.message })
        }
        res.status(500).json({ message: "something went wrong" })
    }
}
/**
 * @description it will take interview id and return the interview report if the interview report belongs to the user
 */
async function interviewRepoerByIdController(req, res) {
    try {
        const { interviewId } = req.params
        const userid = req.user.id
        if (!interviewId) {
            return res.status(400).json({ message: "please give interview id" })
        }
        //NOTE - ensure users can only access their own interview reports.
        const interviewReport = await interviewReportModel.findOne({
            _id: interviewId,
            user: userid
        })

        if (!interviewReport) {
            return res.status(404).json({ message: "no report found with this id" })
        }

        return res.status(200).json({ message: "interview report fetched successfully", interviewReport })
    } catch (err) {
        console.log(err)
        res.status(500).json({ message: "something went wrong" })
    }
}

/**
 * @description it wil return all user interview report
 *  */

async function getAllInterviewReports(req, res) {
    try {
        const userAllReports = await interviewReportModel.find({ user: req.user.id }).sort({ createdAt: -1 }).select("-resume -selfDescription -jobDescription -__v -technicalQuestions -behavioralQuestions -skillGaps -preparationPlan")
        return res.status(200).json({ message: "interview reports fetched successfully", userAllReports })
    } catch (err) {
        console.log(err)
        res.status(500).json({ message: "something went wrong" })
    }

}
/**
 * @description it wil return pdf of resume which is sutable for the job dexcription 
 *  */
async function genereateJobReadyPdfController(req, res) {
    try {
        const { interviewId } = req.params

        const interviewReport = await interviewReportModel.findById(interviewId)

        if (!interviewReport) {
            return res.status(404).json({
                success: false,
                message: 'Interview report not found'
            })
        }

        const pdfBuffer = await generateResumePdf({
            resume: interviewReport.resume,
            selfDescription: interviewReport.selfDescription,
            jobDescription: interviewReport.jobDescription
        })

        res.setHeader("Content-Type", "application/pdf")
        res.setHeader(
            "Content-Disposition",
            "attachment; filename=job-ready-resume.pdf"
        )

        return res.send(pdfBuffer)

    } catch (err) {
        console.log(err)
        return res.status(500).json({
            success: false,
            message: "Something went wrong"
        })
    }
}
module.exports = { generateInterviewController, interviewRepoerByIdController, getAllInterviewReports, genereateJobReadyPdfController }
